// src/pages/KhaiBaoCoSo.js
import React, { useState, useCallback, useEffect } from 'react';
import axios from 'axios';
import * as XLSX from 'xlsx'; // Import thư viện xlsx
import './KhaiBaoCoSo.css'; // Import file CSS
import speciesOptions from '../data/speciesData'; // Import danh sách loài từ file mới

function KhaiBaoCoSo() {
  // Initial form state for resetting
  const initialFormState = {
    // Thông tin cơ sở
    tenCoSo: '', tinhThanhPho: '', xaPhuong: '', diaChiCoSo: '', vido: '', kinhdo: '',
    loaiHinhCoSo: '', // Đã bỏ trong form thủ công, nhưng vẫn có thể nhận từ CSV
    ngayThanhLap: '', giayPhepKinhDoanh: '', // giayPhepKinhDoanh là Số giấy phép kinh doanh

    // Người đại diện
    tenNguoiDaiDien: '', namSinh: '', soCCCD: '', ngayCapCCCD: '', noiCapCCCD: '',
    soDienThoaiNguoiDaiDien: '', diaChiNguoiDaiDien: '',
    emailNguoiDaiDien: '', // Đã bỏ trong form thủ công, nhưng vẫn có thể nhận từ CSV

    // Cơ sở gây nuôi
    mucDichNuoi: '', hinhThucNuoi: '', maSoCoSoGayNuoi: '', tongDan: '',

    // Cơ sở kinh doanh, chế biến gỗ
    loaiHinhKinhDoanhGo: '', nganhNgheKinhDoanhGo: '', khoiLuong: '',

    // Tên lâm sản và Tên khoa học (áp dụng cho cả hai loại hình)
    tenLamSan: '',
    tenKhoaHoc: '',

    // Các trường chung khác
    trangThai: '',
    loaiCoSoDangKy: '',
    ghiChu: '',

    // Các trường giấy phép
    licenseNumber: '', // Đã bỏ trong form thủ công, nhưng vẫn có thể nhận từ CSV
    issueDate: '',
    expiryDate: '',

    species: [],
  };

  const [form, setForm] = useState(initialFormState);
  const [successMessage, setSuccessMessage] = useState('');
  const [errorMessage, setErrorMessage] = useState('');
  const [csvFile, setCsvFile] = useState(null);
  const [excelData, setExcelData] = useState([]); // Tên state này vẫn được dùng cho dữ liệu từ CSV
  const [isLoading, setIsLoading] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);
  const [showManualSpeciesInput, setShowManualSpeciesInput] = useState(false);
  const [bulkErrors, setBulkErrors] = useState([]); // New state to store bulk upload errors

  useEffect(() => {
    const token = localStorage.getItem('token');
    setIsAdmin(true); // Giả định là admin cho mục đích demo
  }, []);

  const resetForm = useCallback(() => {
    setForm(initialFormState);
    setSuccessMessage('');
    setErrorMessage('');
    setBulkErrors([]); // Reset bulk errors
    setShowManualSpeciesInput(false);
  }, [initialFormState]);

  const resetCsvUpload = useCallback(() => {
    setCsvFile(null);
    setExcelData([]);
    setSuccessMessage('');
    setErrorMessage('');
    setBulkErrors([]); // Reset bulk errors
  }, []);

  const handleChange = (e) => {
    const { name, value, type } = e.target;
    let newValue = type === 'number' ? (value === '' ? '' : Number(value)) : value;

    if (name === 'tenLamSan') {
      if (newValue === 'Nhập thủ công') {
        setShowManualSpeciesInput(true);
        setForm(prevForm => ({
          ...prevForm,
          [name]: '',
          tenKhoaHoc: ''
        }));
      } else {
        setShowManualSpeciesInput(false);
        const selectedSpecies = speciesOptions.find(s => s.tenLamSan === newValue);
        setForm(prevForm => ({
          ...prevForm,
          [name]: newValue,
          tenKhoaHoc: selectedSpecies ? selectedSpecies.tenKhoaHoc : ''
        }));
      }
    } else {
      setForm({ ...form, [name]: newValue });
    }
  };

  const validateForm = () => {
    setSuccessMessage('');
    setErrorMessage('');
    setBulkErrors([]); // Clear bulk errors on manual form validation

    // Kiểm tra các trường bắt buộc của FarmSchema
    if (!form.tenCoSo || form.tenCoSo.trim() === '') {
      setErrorMessage('Tên cơ sở là bắt buộc.');
      return false;
    }
    if (!form.tenNguoiDaiDien || form.tenNguoiDaiDien.trim() === '') {
      setErrorMessage('Họ và tên người đại diện là bắt buộc.');
      return false;
    }
    if (!form.soCCCD || form.soCCCD.trim() === '') {
      setErrorMessage('Số CCCD/Hộ chiếu là bắt buộc.');
      return false;
    }
    if (!form.loaiCoSoDangKy || form.loaiCoSoDangKy.trim() === '') {
      setErrorMessage('Loại cơ sở đăng ký là bắt buộc.');
      return false;
    }

    // Cập nhật logic kiểm tra cho Cơ sở gây nuôi
    const isGayNuoiFilled = (form.mucDichNuoi && form.mucDichNuoi.trim() !== '') ||
                           (form.hinhThucNuoi && form.hinhThucNuoi.trim() !== '') ||
                           (form.maSoCoSoGayNuoi && form.maSoCoSoGayNuoi.trim() !== '') ||
                           (form.tongDan && String(form.tongDan).trim() !== '');

    // Cập nhật logic kiểm tra cho Cơ sở kinh doanh, chế biến gỗ
    const isKinhDoanhGoFilled = (form.loaiHinhKinhDoanhGo && form.loaiHinhKinhDoanhGo.trim() !== '') ||
                               (form.nganhNgheKinhDoanhGo && form.nganhNgheKinhDoanhGo.trim() !== '') ||
                               (form.khoiLuong && String(form.khoiLuong).trim() !== '');

    if (form.loaiCoSoDangKy === 'Đăng ký cơ sở gây nuôi') {
      if (!isGayNuoiFilled) {
        setErrorMessage('Vui lòng điền đầy đủ thông tin cho mục "Cơ sở gây nuôi".');
        return false;
      }
      if (isKinhDoanhGoFilled) {
        setErrorMessage('Không được điền thông tin "Cơ sở kinh doanh, chế biến gỗ" khi đã chọn "Đăng ký cơ sở gây nuôi".');
        return false;
      }
    } else if (form.loaiCoSoDangKy === 'Đăng ký cơ sở kinh doanh, chế biến gỗ') {
      if (!isKinhDoanhGoFilled) {
        setErrorMessage('Vui lòng điền đầy đủ thông tin cho mục "Cơ sở kinh doanh, chế biến gỗ".');
        return false;
      }
      if (isGayNuoiFilled) {
        setErrorMessage('Không được điền thông tin "Cơ sở gây nuôi" khi đã chọn "Đăng ký cơ sở kinh doanh, chế biến gỗ".');
        return false;
      }
    } else { // Nếu chưa chọn loại cơ sở đăng ký
      if (isGayNuoiFilled || isKinhDoanhGoFilled) {
        setErrorMessage('Vui lòng chọn "Loại cơ sở đăng ký" trước khi điền thông tin chi tiết.');
        return false;
      }
    }

    // Kiểm tra riêng cho tenLamSan và tenKhoaHoc nếu một trong hai loại hình được chọn
    if (form.loaiCoSoDangKy === 'Đăng ký cơ sở gây nuôi' || form.loaiCoSoDangKy === 'Đăng ký cơ sở kinh doanh, chế biến gỗ') {
        if (showManualSpeciesInput && (!form.tenLamSan || form.tenLamSan.trim() === '' || !form.tenKhoaHoc || form.tenKhoaHoc.trim() === '')) {
            setErrorMessage('Vui lòng điền Tên lâm sản và Tên khoa học khi chọn "Nhập thủ công".');
            return false;
        }
    }

    return true;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!validateForm()) return;

    setIsLoading(true);
    setBulkErrors([]); // Clear bulk errors
    try {
      const token = localStorage.getItem('token');
      if (!token) {
        setErrorMessage('Bạn chưa đăng nhập. Vui lòng đăng nhập lại.');
        setIsLoading(false);
        return;
      }

      // Chuẩn bị dữ liệu gửi đi, loại bỏ các trường không cần thiết hoặc rỗng
      const dataToSend = { ...form };
      // Các trường này có thể có giá trị từ CSV nhưng không có trong form thủ công
      // Nên không xóa chúng ở đây, mà chỉ xóa các trường đặc thù theo loaiCoSoDangKy

      // Chuyển đổi ngày tháng về định dạng ISO string nếu có giá trị
      if (dataToSend.ngayThanhLap) dataToSend.ngayThanhLap = new Date(dataToSend.ngayThanhLap).toISOString();
      if (dataToSend.ngayCapCCCD) dataToSend.ngayCapCCCD = new Date(dataToSend.ngayCapCCCD).toISOString();
      if (dataToSend.issueDate) dataToSend.issueDate = new Date(dataToSend.issueDate).toISOString();
      if (dataToSend.expiryDate) dataToSend.expiryDate = new Date(dataToSend.expiryDate).toISOString();

      // Xóa các trường không liên quan đến loại hình đăng ký được chọn
      // Giữ lại các trường loaiHinhCoSo, emailNguoiDaiDien, licenseNumber nếu chúng có trong schema và CSV
      if (dataToSend.loaiCoSoDangKy === 'Đăng ký cơ sở gây nuôi') {
        delete dataToSend.loaiHinhKinhDoanhGo;
        delete dataToSend.nganhNgheKinhDoanhGo;
        delete dataToSend.khoiLuong;
      } else if (dataToSend.loaiCoSoDangKy === 'Đăng ký cơ sở kinh doanh, chế biến gỗ') {
        delete dataToSend.mucDichNuoi;
        delete dataToSend.hinhThucNuoi;
        delete dataToSend.maSoCoSoGayNuoi;
        delete dataToSend.tongDan;
      } else { // Nếu không chọn loại hình đăng ký cụ thể, xóa tất cả các trường đặc thù
        delete dataToSend.mucDichNuoi;
        delete dataToSend.hinhThucNuoi;
        delete dataToSend.maSoCoSoGayNuoi;
        delete dataToSend.tongDan;
        delete dataToSend.loaiHinhKinhDoanhGo;
        delete dataToSend.nganhNgheKinhDoanhGo;
        delete dataToSend.khoiLuong;
        delete dataToSend.tenLamSan; // Xóa nếu không thuộc loại hình nào
        delete dataToSend.tenKhoaHoc; // Xóa nếu không thuộc loại hình nào
      }

      const response = await axios.post(
        'http://localhost:10000/api/farms',
        dataToSend, // Gửi dữ liệu đã được làm sạch
        { headers: { Authorization: `Bearer ${token}` } }
      );

      console.log('Success:', response.data);
      setSuccessMessage('Thông tin cơ sở đã được lưu thành công!');
      resetForm();
    } catch (error) {
      setErrorMessage('Đã xảy ra lỗi khi lưu thông tin. Vui lòng thử lại.');
      console.error('Error saving farm:', error.response?.data || error.message);
      if (error.response && error.response.data && error.response.data.errors) {
        const validationErrors = Object.values(error.response.data.errors).map(err => err.message).join('; ');
        setErrorMessage(`Lỗi xác thực: ${error.response.data.message || 'Một số bản ghi không hợp lệ.'}`);
      } else if (error.response && error.response.data && error.response.data.message) {
        setErrorMessage(`Đã xảy ra lỗi: ${error.response.data.message}`);
      }
    } finally {
      setIsLoading(false);
    }
  };

  // Helper function to parse date values from CSV/Excel
  const parseDateFromCsv = (dateValue) => {
    if (!dateValue) return '';

    // If it's already a Date object (from XLSX cellDates: true or raw: false)
    if (dateValue instanceof Date) {
      return isNaN(dateValue.getTime()) ? '' : dateValue.toISOString().split('T')[0];
    }

    // If it's an Excel serial number (number)
    if (typeof dateValue === 'number') {
      const date = new Date(Math.round((dateValue - 25569) * 86400 * 1000));
      return isNaN(date.getTime()) ? '' : date.toISOString().split('T')[0];
    }

    // If it's a string, try to parse various formats
    const dateStr = String(dateValue).trim();
    // Try DD/MM/YYYY
    const parts = dateStr.split('/');
    if (parts.length === 3) {
      const day = parseInt(parts[0], 10);
      const month = parseInt(parts[1], 10) - 1; // Month is 0-indexed
      const year = parseInt(parts[2], 10);
      const date = new Date(year, month, day);
      return isNaN(date.getTime()) ? '' : date.toISOString().split('T')[0];
    }
    // Try YYYY-MM-DD or other ISO-like formats
    const date = new Date(dateStr);
    return isNaN(date.getTime()) ? '' : date.toISOString().split('T')[0];
  };

  // Function to handle CSV file upload
  const handleFileUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      setCsvFile(file);
      const reader = new FileReader();
      reader.onload = (event) => {
        try {
          const data = event.target.result;
          // Use type: 'binary' for better compatibility with various CSV encodings
          // Set FS: ';' for semicolon delimiter as per user's CSV
          const workbook = XLSX.read(data, { type: 'binary', cellDates: true, FS: ';' });

          const sheetName = workbook.SheetNames[0];
          const worksheet = workbook.Sheets[sheetName];

          // Use sheet_to_json without header: 1 to get array of objects with header names as keys
          // defval: '' will ensure undefined/null cells become empty strings
          const json = XLSX.utils.sheet_to_json(worksheet, { raw: false, defval: '' });

          console.log("Raw JSON data from CSV (from XLSX.utils.sheet_to_json):", json);
          // Log all headers found by XLSX
          console.log("Headers found in CSV by XLSX:", Object.keys(json.length > 0 ? json[0] : {}));


          const mappedData = json.map(row => {
            const farm = {};

            // Log the raw row data for debugging
            console.log("Processing row:", row);

            // Directly access properties using exact header names from the CSV template
            // Use parseDateFromCsv for all date fields
            // Use String() and trim() for string fields to ensure consistency
            // Use Number() for numeric fields, handling potential empty strings
            farm.tenCoSo = String(row['Tên cơ sở'] || '').trim();
            farm.tinhThanhPho = String(row['Tỉnh (TP)'] || '').trim(); // Changed from 'Tỉnh (Thành phố)'
            farm.xaPhuong = String(row['Xã (Phường)'] || '').trim();
            farm.diaChiCoSo = String(row['Địa chỉ cơ sở'] || '').trim(); // Changed from 'Địa chỉ'
            farm.vido = String(row['Vĩ độ'] || '').trim();
            farm.kinhdo = String(row['Kinh độ'] || '').trim();
            farm.loaiHinhCoSo = String(row['Loại hình cơ sở'] || '').trim(); // Giữ lại
            farm.ngayThanhLap = parseDateFromCsv(row['Ngày thành lập']);
            farm.giayPhepKinhDoanh = String(row['Số GPKD'] || '').trim(); // Changed from 'Số giấy phép kinh doanh'

            farm.tenNguoiDaiDien = String(row['Người đại diện'] || '').trim(); // Changed from 'Họ và tên người đại diện'
            // Ensure namSinh is parsed as a number, or undefined if empty/invalid
            farm.namSinh = row['Năm sinh'] !== '' && row['Năm sinh'] !== null ? Number(row['Năm sinh']) : undefined;
            farm.soCCCD = String(row['Số CCCD/Hộ chiếu'] || '').trim();
            farm.ngayCapCCCD = parseDateFromCsv(row['Ngày cấp CCCD']);
            farm.noiCapCCCD = String(row['Nơi cấp CCCD'] || '').trim();
            farm.soDienThoaiNguoiDaiDien = String(row['SĐT Người đại diện'] || '').trim(); // Changed from 'Số điện thoại người đại diện'
            farm.diaChiNguoiDaiDien = String(row['Địa chỉ Người đại diện'] || '').trim(); // Changed from 'Địa chỉ người đại diện'
            farm.emailNguoiDaiDien = String(row['Email Người đại diện'] || '').trim(); // Giữ lại

            farm.mucDichNuoi = String(row['Mục đích nuôi'] || '').trim();
            farm.hinhThucNuoi = String(row['Hình thức nuôi'] || '').trim();
            farm.maSoCoSoGayNuoi = String(row['Mã số CS gây nuôi'] || '').trim(); // Changed from 'Mã số cơ sở gây nuôi'
            farm.tongDan = row['Tổng đàn'] !== '' && row['Tổng đàn'] !== null ? Number(row['Tổng đàn']) : undefined; // Có trong CSV mới

            farm.loaiHinhKinhDoanhGo = String(row['Loại hình KD gỗ'] || '').trim(); // Changed from 'Loại hình kinh doanh gỗ'
            farm.nganhNgheKinhDoanhGo = String(row['Ngành nghề KD gỗ'] || '').trim(); // Changed from 'Ngành nghề kinh doanh gỗ'
            farm.khoiLuong = String(row['Khối lượng'] || '').trim();

            farm.tenLamSan = String(row['Tên lâm sản'] || '').trim();
            farm.tenKhoaHoc = String(row['Tên khoa học'] || '').trim();

            farm.trangThai = String(row['Trạng thái'] || '').trim();
            farm.ghiChu = String(row['Ghi chú'] || '').trim();

            farm.licenseNumber = String(row['Số giấy phép'] || '').trim(); // Giữ lại
            farm.issueDate = parseDateFromCsv(row['Ngày cấp']); // This is the general license issue date
            farm.expiryDate = parseDateFromCsv(row['Ngày hết hạn']); // Có trong CSV mới

            // Log the raw value of 'Loại CS Đăng ký' from the row
            const rawLoaiCoSoDangKyValue = row['Loại CS Đăng ký'];
            console.log(`Raw 'Loại CS Đăng ký' from CSV: "${rawLoaiCoSoDangKyValue}"`);

            // Ensure loaiCoSoDangKy is trimmed and matches enum values exactly
            let loaiCoSoDangKyValue = String(rawLoaiCoSoDangKyValue || '').trim();
            console.log(`Trimmed 'Loại CS Đăng ký' value: "${loaiCoSoDangKyValue}"`);

            // Normalize values for loaiCoSoDangKy to match schema enum
            if (loaiCoSoDangKyValue === 'Đăng ký cơ sở gây nuôi' || loaiCoSoDangKyValue === 'Đăng ký cơ sở kinh doanh, chế biến gỗ') {
                farm.loaiCoSoDangKy = loaiCoSoDangKyValue;
            } else {
                farm.loaiCoSoDangKy = ''; // Set to empty if not valid enum, will trigger validation error
                console.error(`Invalid 'Loại CS Đăng ký' value found: "${rawLoaiCoSoDangKyValue}". Setting to empty to trigger validation error.`);
            }

            // Trường species (Không xử lý từ CSV đơn giản, giữ là mảng rỗng hoặc logic phức tạp hơn)
            farm.species = [];

            return farm;
          });
          setExcelData(mappedData);
          setSuccessMessage(`Đã đọc thành công ${json.length} dòng dữ liệu từ CSV. Vui lòng nhấn "Tải lên hàng loạt" để lưu.`);
          setErrorMessage('');
          setBulkErrors([]); // Clear any previous bulk errors
        } catch (error) {
          setErrorMessage('Lỗi khi đọc file CSV. Vui lòng đảm bảo file đúng định dạng và có các cột tiêu đề phù hợp.');
          console.error('Error reading CSV file:', error);
          setBulkErrors([]); // Clear any previous bulk errors
        }
      };
      // Change from readAsText to readAsBinaryString for better CSV compatibility
      reader.readAsBinaryString(file);
    }
  };

  // Function to handle bulk data upload from Excel
  const handleBulkSubmit = async () => {
    setSuccessMessage('');
    setErrorMessage('');
    setBulkErrors([]); // Clear previous bulk errors

    if (excelData.length === 0) {
      setErrorMessage('Không có dữ liệu từ CSV để tải lên.');
      return;
    }

    setIsLoading(true);
    try {
      const token = localStorage.getItem('token');
      if (!token) {
        setErrorMessage('Bạn chưa đăng nhập. Vui lòng đăng nhập lại.');
        setIsLoading(false);
        return;
      }

      const response = await axios.post(
        'http://localhost:10000/api/farms/bulk', // New API endpoint for bulk upload
        excelData,
        { headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' } }
      );

      console.log('Bulk upload success:', response.data);
      setSuccessMessage(`Đã lưu thành công ${response.data.savedCount || excelData.length} cơ sở từ file CSV!`);
      if (response.data.errors && response.data.errors.length > 0) {
        setBulkErrors(response.data.errors);
        setErrorMessage(`Có ${response.data.errors.length} cơ sở không thể lưu do lỗi. Vui lòng xem chi tiết bên dưới.`);
      }
      resetCsvUpload(); // Reset CSV file and data after submission
    } catch (error) {
      setErrorMessage('Đã xảy ra lỗi khi tải lên dữ liệu hàng loạt. Vui lòng thử lại.');
      console.error('Error bulk uploading farms:', error.response?.data || error.message);

      if (error.response && error.response.data) {
        if (error.response.data.errors && Array.isArray(error.response.data.errors)) {
          setBulkErrors(error.response.data.errors);
          setErrorMessage(`Đã xảy ra lỗi khi tải lên. Có ${error.response.data.errors.length} cơ sở không thể lưu. Vui lòng xem chi tiết bên dưới.`);
        } else if (error.response.data.message) {
          setErrorMessage(`Lỗi: ${error.response.data.message}`);
        }
      }
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="khai-bao-container">
      <h1>Khai báo cơ sở</h1>

      {/* Message Area */}
      {isLoading && <p className="loading-message">Đang xử lý...</p>}
      {successMessage && <p className="success-message">{successMessage}</p>}
      {errorMessage && <p className="error-message">{errorMessage}</p>}

      {/* Display Bulk Errors */}
      {bulkErrors.length > 0 && (
        <div className="bulk-errors-container">
          <h3>Chi tiết lỗi tải lên hàng loạt:</h3>
          <ul>
            {bulkErrors.map((err, index) => (
              <li key={index} className="bulk-error-item">
                <p><strong>Cơ sở:</strong> {err.data.tenCoSo || 'Không rõ tên'}</p>
                <p><strong>Lỗi:</strong> {err.message}</p>
                {err.error && typeof err.error === 'object' && (
                  <ul>
                    {Object.entries(err.error).map(([field, msg]) => (
                      <li key={field}>- {field}: {msg}</li>
                    ))}
                  </ul>
                )}
                {err.error && typeof err.error === 'string' && (
                    <p>- Chi tiết: {err.error}</p>
                )}
              </li>
            ))}
          </ul>
        </div>
      )}

      {/* Manual Form Submission Section */}
      <form onSubmit={handleSubmit}>
        <section className="khai-bao-section">
          <h2>Thông tin cơ sở (Khai báo thủ công)</h2>
          <div className="form-grid">
            <div className="form-group">
              <label htmlFor="tenCoSo">Tên cơ sở:</label>
              <input type="text" id="tenCoSo" name="tenCoSo" value={form.tenCoSo} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label htmlFor="tinhThanhPho">Tỉnh (Thành phố):</label>
              <input type="text" id="tinhThanhPho" name="tinhThanhPho" value={form.tinhThanhPho} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label htmlFor="xaPhuong">Xã (Phường):</label>
              <input type="text" id="xaPhuong" name="xaPhuong" value={form.xaPhuong} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label htmlFor="diaChiCoSo">Địa chỉ:</label>
              <input type="text" id="diaChiCoSo" name="diaChiCoSo" value={form.diaChiCoSo} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label htmlFor="vido">Vĩ độ:</label>
              <input type="text" id="vido" name="vido" value={form.vido} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="kinhdo">Kinh độ:</label>
              <input type="text" id="kinhdo" name="kinhdo" value={form.kinhdo} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="loaiHinhCoSo">Loại hình cơ sở:</label>
              <input type="text" id="loaiHinhCoSo" name="loaiHinhCoSo" value={form.loaiHinhCoSo} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="ngayThanhLap">Ngày thành lập:</label>
              <input type="date" id="ngayThanhLap" name="ngayThanhLap" value={form.ngayThanhLap} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="giayPhepKinhDoanh">Số giấy phép kinh doanh:</label>
              <input type="text" id="giayPhepKinhDoanh" name="giayPhepKinhDoanh" value={form.giayPhepKinhDoanh} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="loaiCoSoDangKy">Loại cơ sở đăng ký:</label>
              <select id="loaiCoSoDangKy" name="loaiCoSoDangKy" value={form.loaiCoSoDangKy} onChange={handleChange} required>
                <option value="">- Chọn loại cơ sở -</option>
                <option value="Đăng ký cơ sở gây nuôi">=> Đăng ký cơ sở gây nuôi</option>
                <option value="Đăng ký cơ sở kinh doanh, chế biến gỗ">=> Đăng ký cơ sở kinh doanh,chế biến gỗ</option>
              </select>
            </div>
            <div className="form-group">
              <label htmlFor="trangThai">Trạng thái:</label>
              <select id="trangThai" name="trangThai" value={form.trangThai} onChange={handleChange}>
                <option value="">- Chọn trạng thái -</option>
                <option value="Hoạt động">Hoạt động</option>
                <option value="Tạm ngưng">Tạm ngưng</option>
                <option value="Nghỉ nuôi">Nghỉ nuôi</option>
              </select>
            </div>
            <div className="form-group">
              <label htmlFor="ghiChu">Ghi chú:</label>
              <input type="text" id="ghiChu" name="ghiChu" value={form.ghiChu} onChange={handleChange} />
            </div>
          </div>
        </section>

        <section className="khai-bao-section">
          <h2>Người đại diện</h2>
          <div className="form-grid">
            <div className="form-group">
              <label htmlFor="tenNguoiDaiDien">Họ và tên:</label>
              <input type="text" id="tenNguoiDaiDien" name="tenNguoiDaiDien" value={form.tenNguoiDaiDien} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label htmlFor="namSinh">Năm sinh:</label>
              <input type="number" id="namSinh" name="namSinh" value={form.namSinh} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="soCCCD">Số CCCD/Hộ chiếu:</label>
              <input type="text" id="soCCCD" name="soCCCD" value={form.soCCCD} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label htmlFor="ngayCapCCCD">Ngày cấp:</label>
              <input type="date" id="ngayCapCCCD" name="ngayCapCCCD" value={form.ngayCapCCCD} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="noiCapCCCD">Nơi cấp:</label>
              <input type="text" id="noiCapCCCD" name="noiCapCCCD" value={form.noiCapCCCD} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="soDienThoaiNguoiDaiDien">Số điện thoại:</label>
              <input type="tel" id="soDienThoaiNguoiDaiDien" name="soDienThoaiNguoiDaiDien" value={form.soDienThoaiNguoiDaiDien} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="diaChiNguoiDaiDien">Địa chỉ:</label>
              <input type="text" id="diaChiNguoiDaiDien" name="diaChiNguoiDaiDien" value={form.diaChiNguoiDaiDien} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="emailNguoiDaiDien">Email:</label>
              <input type="email" id="emailNguoiDaiDien" name="emailNguoiDaiDien" value={form.emailNguoiDaiDien} onChange={handleChange} />
            </div>
          </div>
        </section>

        {form.loaiCoSoDangKy === 'Đăng ký cơ sở gây nuôi' && (
          <section className="khai-bao-section">
            <h3>Cơ sở gây nuôi</h3>
            <div className="form-grid">
              <div className="form-group">
                <label htmlFor="mucDichNuoi">Mục đích nuôi:</label>
                <select id="mucDichNuoi" name="mucDichNuoi" value={form.mucDichNuoi} onChange={handleChange}>
                  <option value="">Chọn mục đích nuôi</option>
                  <option value="Nuôi thương mại">Nuôi thương mại</option>
                  <option value="Nuôi phi thương mại">Nuôi phi thương mại</option>
                </select>
              </div>
              <div className="form-group">
                <label htmlFor="hinhThucNuoi">Hình thức nuôi:</label>
                <select id="hinhThucNuoi" name="hinhThucNuoi" value={form.hinhThucNuoi} onChange={handleChange}>
                  <option value="">Chọn hình thức nuôi</option>
                  <option value="Sinh trưởng">Sinh trưởng</option>
                  <option value="Sinh sản">Sinh sản</option>
                  <option value="Sinh trưởng và sinh sản">Sinh trưởng và sinh sản</option>
                </select>
              </div>
              <div className="form-group">
                <label htmlFor="maSoCoSoGayNuoi">Mã số cơ sở:</label>
                <input type="text" id="maSoCoSoGayNuoi" name="maSoCoSoGayNuoi" value={form.maSoCoSoGayNuoi} onChange={handleChange} />
              </div>
              <div className="form-group">
                <label htmlFor="tongDan">Tổng đàn:</label>
                <input type="number" id="tongDan" name="tongDan" value={form.tongDan} onChange={handleChange} />
              </div>
            </div>
          </section>
        )}

        {form.loaiCoSoDangKy === 'Đăng ký cơ sở kinh doanh, chế biến gỗ' && (
          <section className="khai-bao-section">
            <h4>Cơ sở kinh doanh, chế biến gỗ</h4>
            <div className="form-grid">
              <div className="form-group">
                <label htmlFor="loaiHinhKinhDoanhGo">Loại hình kinh doanh gỗ:</label>
                <select id="loaiHinhKinhDoanhGo" name="loaiHinhKinhDoanhGo" value={form.loaiHinhKinhDoanhGo} onChange={handleChange}>
                  <option value="">Chọn loại hình kinh doanh</option>
                  <option value="Trại cưa">Trại cưa</option>
                  <option value="Trại mộc">Trại mộc</option>
                  <option value="Trang trí nội thất">Trang trí nội thất</option>
                </select>
              </div>
              <div className="form-group">
                <label htmlFor="nganhNgheKinhDoanhGo">Ngành nghề:</label>
                <select id="nganhNgheKinhDoanhGo" name="nganhNgheKinhDoanhGo" value={form.nganhNgheKinhDoanhGo} onChange={handleChange}>
                  <option value="">Chọn ngành nghề</option>
                  <option value="Thương mại">Thương mại</option>
                  <option value="Cưa gia công và mộc">Cưa gia công và mộc</option>
                  <option value="Chế biến mộc và thương mại">Chế biến mộc và thương mại</option>
                </select>
              </div>
              <div className="form-group">
                <label htmlFor="khoiLuong">Khối lượng:</label>
                <input type="text" id="khoiLuong" name="khoiLuong" value={form.khoiLuong} onChange={handleChange} />
              </div>
            </div>
          </section>
        )}

        {/* Tên lâm sản và Tên khoa học - Hiển thị cho cả hai loại hình khi được chọn */}
        {(form.loaiCoSoDangKy === 'Đăng ký cơ sở gây nuôi' || form.loaiCoSoDangKy === 'Đăng ký cơ sở kinh doanh, chế biến gỗ') && (
            <section className="khai-bao-section">
                <h3>Thông tin Loài</h3>
                <div className="form-grid">
                    <div className="form-group">
                        <label htmlFor="tenLamSan">Tên lâm sản:</label>
                        {showManualSpeciesInput ? (
                            <input
                                type="text"
                                id="tenLamSan"
                                name="tenLamSan"
                                value={form.tenLamSan}
                                onChange={handleChange}
                                placeholder="Nhập tên lâm sản"
                            />
                        ) : (
                            <select id="tenLamSan" name="tenLamSan" value={form.tenLamSan} onChange={handleChange}>
                                <option value="">Chọn tên lâm sản</option>
                                {speciesOptions.map((option, index) => (
                                    <option key={index} value={option.tenLamSan}>
                                        {option.tenLamSan}
                                    </option>
                                ))}
                                <option value="Nhập thủ công">Nhập thủ công</option>
                            </select>
                        )}
                    </div>
                    <div className="form-group">
                        <label htmlFor="tenKhoaHoc">Tên khoa học:</label>
                        {showManualSpeciesInput ? (
                            <input
                                type="text"
                                id="tenKhoaHoc"
                                name="tenKhoaHoc"
                                value={form.tenKhoaHoc}
                                onChange={handleChange}
                                placeholder="Nhập tên khoa học"
                            />
                        ) : (
                            <input type="text" id="tenKhoaHoc" name="tenKhoaHoc" value={form.tenKhoaHoc} readOnly />
                        )}
                    </div>
                </div>
            </section>
        )}

        <section className="khai-bao-section">
          <h4>Thông tin Giấy phép</h4>
          <div className="form-grid">
            <div className="form-group">
              <label htmlFor="licenseNumber">Số giấy phép:</label>
              <input type="text" id="licenseNumber" name="licenseNumber" value={form.licenseNumber} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="issueDate">Ngày cấp:</label>
              <input type="date" id="issueDate" name="issueDate" value={form.issueDate} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="expiryDate">Ngày hết hạn:</label>
              <input type="date" id="expiryDate" name="expiryDate" value={form.expiryDate} onChange={handleChange} />
            </div>
          </div>
        </section>

        <button type="submit" className="submit-button" disabled={isLoading}>
          {isLoading ? 'Đang lưu...' : 'Lưu thông tin'}
        </button>
      </form>

      {isAdmin && <hr className="section-divider" />}

      {isAdmin && (
        <section className="khai-bao-section excel-upload-section">
          <div className="file-upload-group">
            <label htmlFor="csvUpload" className="file-upload-label">
              Chọn file CSV (.csv):
            </label>
            <input
              type="file"
              id="csvUpload"
              accept=".csv"
              onChange={handleFileUpload}
              className="file-input"
            />
            {csvFile && <span className="file-name">{csvFile.name}</span>}
          </div>
          {excelData.length > 0 && (
            <div className="excel-preview-info">
              <p>Đã đọc được {excelData.length} dòng dữ liệu từ CSV. Vui lòng nhấn "Tải lên hàng loạt" để lưu.</p>
              <button
                onClick={handleBulkSubmit}
                className="submit-button bulk-upload-button"
                disabled={isLoading}
              >
                {isLoading ? 'Đang tải...' : `Tải lên hàng loạt (${excelData.length} cơ sở)`}
              </button>
              <button
                onClick={resetCsvUpload}
                className="clear-excel-button"
                disabled={isLoading}
              >
                Xóa dữ liệu CSV
              </button>
            </div>
          )}
        </section>
      )}
    </div>
  );
}

export default KhaiBaoCoSo;
